```python
def count_tilings_4xN(N: int) -> int:
    MOD = 10**9 + 7
    dp = [[0] * (1 << 4) for _ in range(2)]
    dp[0][0] = 1

    for i in range(N):
        for j in range(4):
            cur = (i * 4 + j) % 2
            nxt = (cur + 1) % 2
            dp[nxt] = [0] * (1 << 4)
            for mask in range(1 << 4):
                if dp[cur][mask] == 0: continue

                # If current cell is already covered by a domino from the left
                if mask & (1 << 3):
                    dp[nxt][mask ^ (1 << 3)] = (dp[nxt][mask ^ (1 << 3)] + dp[cur][mask]) % MOD
                else:
                    # Try placing horizontal domino (covers this cell and the one to the right)
                    if i + 1 < N:
                        dp[nxt][mask | 1] = (dp[nxt][mask | 1] + dp[cur][mask]) % MOD

                    # Try placing vertical domino (covers this cell and the one below)
                    if j + 1 < 4 and not (mask & (1 << 0)):
                        dp[nxt][mask | (1 << 0)] = (dp[nxt][mask | (1 << 0)] + dp[cur][mask]) % MOD

    return dp[(N * 4) % 2][0]
