        min_edge = None
        for u in visited:
            for v, weight in graph[u]:
                if v not in visited:
                    if min_edge is None or weight < min_edge[2]:
                        min_edge = (u, v, weight)

        # Optimization: To speed up, if we find another edge with the EXACT SAME minimum weight
        # crossing the cut, we can safely add it too, as it must also be part of the MST.
        edges_to_add = [min_edge]
        for u in visited:
            for v, weight in graph[u]:
                if v not in visited and (u, v, weight) != min_edge and weight == min_edge[2]:
                    edges_to_add.append((u, v, weight))

        for u, v, w in edges_to_add:
            if v not in visited: # Prevent cycles if multiple edges point to the same unvisited node
                mst_edges.append((u, v, w))
                visited.add(v)
    return mst_edges
